71: 		c.Nullable = false
72: 		res = DB_BigInt
73: 	case DB_Bytea:
74: 		res = DB_Blob
75: 	case DB_TimeStampz:
76: 		res = DB_Char
77: 		c.Length = 64
78: 	case DB_NVarchar:
79: 		res = DB_Varchar
80: 	case DB_Uuid:
81: 		res = DB_Char
82: 		c.Length = 36
83: 	default:
