273: func (db *MySQLDialect) Lock(cfg LockCfg) error {
274: 	query := "SELECT GET_LOCK(?, ?)"
275: 	var success sql.NullBool
276: 
277: 	// trying to obtain the lock with the specific name
278: 	// the lock is exclusive per session and is released explicitly by executing RELEASE_LOCK() or implicitly when the session terminates
